// Read GHL token renewal date from N8N static data or environment variable.
// TOKEN_RENEWED_AT should be set in N8N environment variables (or update manually after each renewal).
// Format: ISO date string e.g. "2026-03-01T00:00:00Z"

const renewedAtStr = $env.GHL_TOKEN_RENEWED_AT ?? process.env.GHL_TOKEN_RENEWED_AT;

if (!renewedAtStr) {
  throw new Error('GHL_TOKEN_RENEWED_AT environment variable is not set in N8N. Set it to the ISO date of last token renewal.');
}

const renewedAt = new Date(renewedAtStr);
if (isNaN(renewedAt.getTime())) {
  throw new Error(`GHL_TOKEN_RENEWED_AT value "${renewedAtStr}" is not a valid ISO date.`);
}

const now = new Date();
const TOKEN_LIFETIME_DAYS = 90;
const expiresAt = new Date(renewedAt.getTime() + TOKEN_LIFETIME_DAYS * 24 * 60 * 60 * 1000);
const daysUntilExpiry = Math.ceil((expiresAt.getTime() - now.getTime()) / (24 * 60 * 60 * 1000));
const daysSinceRenewal = Math.floor((now.getTime() - renewedAt.getTime()) / (24 * 60 * 60 * 1000));

// Alert thresholds
const ALERT_DAY_75 = daysUntilExpiry <= 15; // 90 - 75 = 15 days left
const ALERT_DAY_80 = daysUntilExpiry <= 10; // 90 - 80 = 10 days left
const ALERT_DAY_85 = daysUntilExpiry <= 5;  // 90 - 85 = 5 days left
const ALERT_EXPIRED = daysUntilExpiry <= 0;

const shouldAlert = ALERT_DAY_75;

let urgency = 'info';
if (ALERT_EXPIRED) urgency = 'critical';
else if (ALERT_DAY_85) urgency = 'critical';
else if (ALERT_DAY_80) urgency = 'high';
else if (ALERT_DAY_75) urgency = 'medium';

return [{
  json: {
    renewedAt: renewedAt.toISOString(),
    expiresAt: expiresAt.toISOString(),
    daysSinceRenewal,
    daysUntilExpiry,
    shouldAlert,
    urgency,
    ALERT_EXPIRED,
    ALERT_DAY_85,
    ALERT_DAY_80,
    ALERT_DAY_75
  }
}];

// Build the Slack alert message based on urgency
const d = $input.first().json;

let emoji = ':warning:';
let urgencyLabel = 'Aviso';

if (d.ALERT_EXPIRED) {
  emoji = ':rotating_light:';
  urgencyLabel = '🔴 CRÍTICO — TOKEN EXPIRADO';
} else if (d.ALERT_DAY_85) {
  emoji = ':rotating_light:';
  urgencyLabel = '🔴 CRÍTICO — expira en ' + d.daysUntilExpiry + ' días';
} else if (d.ALERT_DAY_80) {
  emoji = ':exclamation:';
  urgencyLabel = '🟠 URGENTE — expira en ' + d.daysUntilExpiry + ' días';
} else {
  emoji = ':warning:';
  urgencyLabel = '🟡 AVISO — expira en ' + d.daysUntilExpiry + ' días';
}

const message = `${emoji} *GHL Token Expiry Alert — ${urgencyLabel}*

*GHL_LOCATION_API_KEY* vence pronto.

• Renovado: ${new Date(d.renewedAt).toLocaleDateString('es-MX')}
• Expira: ${new Date(d.expiresAt).toLocaleDateString('es-MX')}
• Días restantes: *${d.daysUntilExpiry}*
• Días transcurridos: ${d.daysSinceRenewal} / 90

*Acción requerida:* Renovar el API key en GHL (Settings → API → Location Key) y actualizar la variable \`GHL_TOKEN_RENEWED_AT\` en N8N con la fecha de hoy.

_Si ya fue renovado, actualiza \`GHL_TOKEN_RENEWED_AT\` para silenciar estas alertas._`;

return [{ json: { message, urgency: d.urgency, daysUntilExpiry: d.daysUntilExpiry } }];
